const EDITABLE_RARITIES = ['purple', 'mythic', 'red'];

// Gemini's model gets silently updated by Google, so its wording for gear tier
// and troop type drifts over time (e.g. it may call gold gear "legendary" or
// "gold" instead of "mythic"). These maps normalize whatever it returns back to
// our canonical tokens so pieces aren't silently discarded on import.
const RARITY_SYNONYMS = {
  grey: 'grey', gray: 'grey', white: 'grey', common: 'grey', basic: 'grey', normal: 'grey',
  green: 'green', uncommon: 'green', lime: 'green', emerald: 'green',
  blue: 'blue', rare: 'blue', cyan: 'blue', aqua: 'blue', sky: 'blue',
  purple: 'purple', epic: 'purple', violet: 'purple', magenta: 'purple', pink: 'purple',
  mythic: 'mythic', mythical: 'mythic', gold: 'mythic', golden: 'mythic',
  yellow: 'mythic', orange: 'mythic', legendary: 'mythic', amber: 'mythic',
  red: 'red', crimson: 'red', scarlet: 'red', ruby: 'red', ascended: 'red', maroon: 'red',
};
const TROOP_SYNONYMS = {
  infantry: 'infantry', inf: 'infantry', foot: 'infantry', footman: 'infantry',
  melee: 'infantry', shield: 'infantry', soldier: 'infantry',
  archer: 'archer', bow: 'archer', ranged: 'archer', ranger: 'archer',
  marksman: 'archer', crosshair: 'archer', hunter: 'archer',
  cavalry: 'cavalry', cav: 'cavalry', horse: 'cavalry', horseman: 'cavalry',
  mounted: 'cavalry', rider: 'cavalry', knight: 'cavalry',
};
const normalizeRarity = (raw) => {
  const k = String(raw || '').toLowerCase().trim();
  if (RARITIES.includes(k)) return k;
  return RARITY_SYNONYMS[k] || null;
};
const normalizeTroop = (raw) => {
  const k = String(raw || '').toLowerCase().trim();
  if (TROOPS.includes(k)) return k;
  return TROOP_SYNONYMS[k] || null;
};
const RARITY_LABEL = { grey: 'Grey', green: 'Green', blue: 'Blue', purple: 'Epic', mythic: 'Mythic', red: 'Red' };
