const T = (key, lang = 'en', vars) => {
  let s = (TRANSLATIONS[lang] && TRANSLATIONS[lang][key])
    || (I18N[key] && (I18N[key][lang] || I18N[key].en))
    || (TRANSLATIONS.en && TRANSLATIONS.en[key])
    || key;
  if (vars) for (const k in vars) s = s.split('{' + k + '}').join(String(vars[k]));
  return s;
};

// ── XP Parts tiers (in-game items that grant Enhancement XP) ──
// Kingshot has 2 tiers: green (10 XP) and purple (100 XP).
const XP_TIERS = [10, 100];
const XP_TIER_LABELS = {
  10:  { name: '10 XP Part',  color: '#22c55e', short: 'Green'  },
  100: { name: '100 XP Part', color: '#a855f7', short: 'Purple' },
};

// Sum: banked XP + (count × tier value) for each XP Part type
const totalXp = (r) => {
  if (!r) return 0;
  let t = r.xpBanked || 0;
  if (r.xpParts) {
    XP_TIERS.forEach(tier => {
      t += tier * (r.xpParts[String(tier)] || 0);
    });
  }
  // Backward compat: legacy `xp` field (single number)
  if (r.xp != null && r.xpBanked == null) t += r.xp;
  return t;
};

// Deduct XP from resources: use banked first, then convert parts (largest first).
// Any over-conversion goes back to banked. Returns the mutated resources object.
const spendXp = (r, amount) => {
  if (!r || amount <= 0) return r;
  if ((r.xpBanked || 0) >= amount) {
    r.xpBanked -= amount;
    return r;
  }
  let deficit = amount - (r.xpBanked || 0);
  r.xpBanked = 0;
  // Use parts largest first to cover deficit
  for (const tier of [...XP_TIERS].sort((a, b) => b - a)) {
    if (deficit <= 0) break;
    const have = r.xpParts?.[String(tier)] || 0;
    if (have === 0) continue;
    const needCount = Math.ceil(deficit / tier);
    const useCount = Math.min(have, needCount);
    r.xpParts[String(tier)] = have - useCount;
    const xpFromParts = useCount * tier;
    if (xpFromParts > deficit) {
      r.xpBanked += xpFromParts - deficit;
      deficit = 0;
    } else {
      deficit -= xpFromParts;
    }
  }
  return r;
};

// ── XP Parts tiers — END ──

// ── Cost formulas ──
// EXACT per-level Enhancement XP. Source: Kingshot Database "Hero Gear
// Enhancement Chart" (matches in-game values). Each entry is the cost to go
// from level L to L+1, so index 0 = step 0→1 (=10 XP) … index 99 = step 99→100
// (=2400 XP). Lower rarities share the same enhancement curve, just capped lower.
const MYTHIC_XP_STEP = [
  10, 15, 20, 25, 30, 35, 40, 45, 50, 55,            //  →1..10
  60, 65, 70, 75, 80, 85, 90, 95, 100, 105,          //  →11..20
  110, 115, 120, 125, 130, 135, 140, 145, 150, 160,  //  →21..30
  170, 180, 190, 200, 210, 220, 230, 240, 250, 270,  //  →31..40
  290, 310, 330, 350, 370, 390, 410, 430, 450, 470,  //  →41..50
  490, 510, 530, 550, 570, 590, 610, 630, 650, 680,  //  →51..60
  710, 740, 770, 800, 830, 860, 890, 920, 950, 990,  //  →61..70
  1030, 1070, 1110, 1150, 1190, 1230, 1270, 1310, 1350, 1400, //  →71..80
  1450, 1500, 1550, 1600, 1650, 1700, 1750, 1800, 1850, 1900, //  →81..90
  1950, 2000, 2050, 2100, 2150, 2200, 2250, 2300, 2350, 2400, //  →91..100
];
const stepXp = (L) => (L >= 0 && L < MYTHIC_XP_STEP.length) ? MYTHIC_XP_STEP[L] : 0;

// EXACT Red per-level costs. Red is displayed 1→100 in-game (a freshly ascended
// piece shows +1; Red +d = game level 100+d). Each array is indexed by the
// *starting* level d for the step d→d+1, so arr[19] is the +19→+20 step, etc.
// Imbuement breakpoints (reaching +20/+40/+60/+80/+100) cost 0 XP but require
// Mithril + Mythic Gear instead. Source: Kingshot Database chart.
const RED_XP_STEP = [
  0, 2500, 2550, 2600, 2650, 2700, 2750, 2800, 2850, 2900, 2950, 3000, 3050, 3100, 3150, 3200, 3250, 3300, 3350,
  0, 3500, 3550, 3600, 3650, 3700, 3750, 3800, 3850, 3900, 3950, 4000, 4050, 4100, 4150, 4200, 4250, 4300, 4350, 4400,
  0, 4450, 4500, 4550, 4600, 4650, 4700, 4750, 4800, 4850, 4900, 4950, 5000, 5050, 5100, 5150, 5200, 5250, 5300, 5350,
  0, 5500, 5600, 5700, 5800, 5900, 6000, 6100, 6200, 6300, 6400, 6500, 6600, 6700, 6800, 6900, 7000, 7100, 7200, 7300,
  0, 7500, 7600, 7700, 7800, 7900, 8000, 8100, 8200, 8300, 8400, 8500, 8600, 8700, 8800, 8900, 9000, 9100, 9200, 9300, 0,
];
// Mithril needed at each imbuement step (0 elsewhere).
const RED_MITHRIL_STEP = (() => { const a = new Array(100).fill(0); a[19]=10; a[39]=20; a[59]=30; a[79]=40; a[99]=50; return a; })();
// Mythic Gears needed at each imbuement step (the 2 for the initial ascend are
// charged by the separate ascend action, so index 0 stays 0 here to avoid double-count).
const RED_MG_STEP = (() => { const a = new Array(100).fill(0); a[19]=3; a[39]=5; a[59]=5; a[79]=10; a[99]=10; return a; })();
const stepRedXp = (L) => (L >= 0 && L < RED_XP_STEP.length) ? RED_XP_STEP[L] : 0;

const XP_PER_LEVEL = {
  // Lower rarities use the same enhancement-XP curve, capped earlier.
  grey: stepXp,
  green: stepXp,
  blue: stepXp,
  purple: stepXp,
  mythic: stepXp,
  // Red is displayed 0→100 in-game (counter restarts after ascending). XP is
  // exact; imbuement steps cost Mithril + Mythic Gear (see RED_MITHRIL_STEP /
  // RED_MG_STEP) rather than XP.
  red: stepRedXp,
};

const HAMMERS_FOR_MASTERY = (toLevel) => toLevel * 10;
const MG_FOR_ASCEND = 2;        // Mythic Gears to ascend Mythic → Red
const MASTERY_FOR_ASCEND = 10;  // Required Mastery Lv before ascending


// ── XP needed to go from current state to target ──
const xpToReach = (rarity, fromLevel, toLevel) => {
  let total = 0;
  for (let L = fromLevel; L < toLevel; L++) total += XP_PER_LEVEL[rarity](L);
  return total;
};
const hammersToReach = (fromMastery, toMastery) => {
  let total = 0;
  for (let M = fromMastery; M < toMastery; M++) total += HAMMERS_FOR_MASTERY(M + 1);
  return total;
};
// Mithril / Mythic-Gear needed to take a RED piece from one level to another
// (imbuement breakpoints only — 0 elsewhere). Levels are Red display 0→100.
const mithrilToReach = (fromLevel, toLevel) => {
  let total = 0;
  for (let L = fromLevel; L < toLevel; L++) total += (RED_MITHRIL_STEP[L] || 0);
  return total;
};
const redMgToReach = (fromLevel, toLevel) => {
  let total = 0;
  for (let L = fromLevel; L < toLevel; L++) total += (RED_MG_STEP[L] || 0);
  return total;
};

