// ═══════════════════════════════════════════════════════════════════
//   PATH ANALYSIS — determine current phase + what's done/pending
// ═══════════════════════════════════════════════════════════════════

// Check if a piece meets a target. Higher rarity always counts as "complete"
// for that target. Same rarity → check level. Different rarity → check the
// rarity rank.
const meetsTarget = (piece, target) => {
  if (!piece) return false;
  if (target.type === 'level') {
    const pieceR = RARITY_RANK[piece.rarity];
    const targetR = RARITY_RANK[target.rarity];
    if (pieceR > targetR) return true;  // higher rarity = already past this
    if (pieceR < targetR) return false; // lower rarity = not done
    return piece.level >= target.level;
  }
  if (target.type === 'ascend') {
    // Ascended means rarity > mythic (i.e., Red)
    return RARITY_RANK[piece.rarity] >= RARITY_RANK.red;
  }
  return false;
};

// Identify the current phase = the first phase with incomplete actions
const identifyCurrentPhase = (gear, path = SHAKES_PATH) => {
  for (const phase of path) {
    if (phase.isStop || phase.isChoose) return phase;
    const allDone = phase.actions.every(a => {
      const piece = gear[`${a.troop}-${a.slot}`];
      return meetsTarget(piece, a);
    });
    if (!allDone) return phase;
  }
  return path[path.length - 1];
};

// For a single action, what's the user's progress?
// Returns: { done: bool, piece, action, gap: { type, fromLevel, toLevel, ... } }
const analyzeAction = (action, gear) => {
  const piece = gear[`${action.troop}-${action.slot}`];
  const done = meetsTarget(piece, action);
  if (done) return { done: true, action, piece };

  if (!piece) {
    return { done: false, action, piece: null, gap: { reason: 'No gear in this slot' } };
  }

  if (action.type === 'level') {
    const pieceR = RARITY_RANK[piece.rarity];
    const targetR = RARITY_RANK[action.rarity];
    if (pieceR < targetR) {
      // Rarity too low — need to push to L100 of current rarity, ascend, ...
      return {
        done: false, action, piece,
        gap: {
          reason: `Needs to be ${RARITY_LABEL[action.rarity]} rarity (currently ${RARITY_LABEL[piece.rarity]})`,
          needsAscension: true,
          fromRarity: piece.rarity,
          toRarity: action.rarity,
          fromLevel: piece.level,
          fromMastery: piece.mastery,
        },
      };
    }
    // Same rarity — just need more levels
    const xpCost = xpToReach(piece.rarity, piece.level, action.level);
    const mithrilCost = piece.rarity === 'red' ? mithrilToReach(piece.level, action.level) : 0;
    const mgCost = piece.rarity === 'red' ? redMgToReach(piece.level, action.level) : 0;
    return {
      done: false, action, piece,
      gap: {
        reason: `Push from L${piece.level} to L${action.level}`,
        fromLevel: piece.level,
        toLevel: action.level,
        xpCost,
        mithrilCost,
        mgCost,
      },
    };
  }

  if (action.type === 'ascend') {
    // Need: Mythic L100 + Mastery 10 + 2 MG
    const ascendReady = piece.rarity === 'mythic' && piece.level === 100 && (piece.mastery || 0) >= MASTERY_FOR_ASCEND;
    if (RARITY_RANK[piece.rarity] >= RARITY_RANK.red) {
      return { done: true, action, piece };
    }
    const xpStillNeeded = piece.rarity === 'mythic' ? xpToReach('mythic', piece.level, 100) : null;
    const hammersStillNeeded = piece.rarity === 'mythic'
      ? hammersToReach(piece.mastery || 0, MASTERY_FOR_ASCEND)
      : null;
    return {
      done: false, action, piece,
      gap: {
        reason: ascendReady ? 'Ready to ascend!' : 'Not ready for ascension yet',
        ascendReady,
        needsXp: xpStillNeeded,
        needsHammers: hammersStillNeeded,
        needsMythicGears: MG_FOR_ASCEND,
        currentRarity: piece.rarity,
        currentLevel: piece.level,
        currentMastery: piece.mastery || 0,
      },
    };
  }
  return { done: false, action, piece };
};

// For the CURRENT phase, compute next-step recommendations.
// Sorts actions by what's most affordable / closest to completion.
const computeNextActions = (gear, resources, path = SHAKES_PATH) => {
  const phase = identifyCurrentPhase(gear, path);
  if (phase.isStop || phase.isChoose) return { phase, actions: [], total: { xp: 0, hammers: 0, mg: 0, mithril: 0 } };

  const analyzed = phase.actions.map(a => analyzeAction(a, gear));
  // Hide "push to Red" actions for pieces that aren't ascended yet — the ascend
  // card for that piece is what's actionable; the level appears once it's Red.
  const remaining = analyzed.filter(x => !x.done && !(x.action.type === 'level' && x.gap && x.gap.needsAscension));

  // Sort: ready-to-ascend > affordable upgrades > big climbs
  remaining.sort((a, b) => {
    const aReady = a.gap?.ascendReady ? 0 : 1;
    const bReady = b.gap?.ascendReady ? 0 : 1;
    if (aReady !== bReady) return aReady - bReady;
    const aCost = (a.gap?.xpCost ?? 0) + (a.gap?.needsXp ?? 0);
    const bCost = (b.gap?.xpCost ?? 0) + (b.gap?.needsXp ?? 0);
    return aCost - bCost;
  });

  // Compute total cost of all remaining actions
  let totalXp = 0, totalHammers = 0, totalMg = 0, totalMithril = 0;
  remaining.forEach(r => {
    if (r.gap?.xpCost) totalXp += r.gap.xpCost;
    if (r.gap?.needsXp) totalXp += r.gap.needsXp;
    if (r.gap?.needsHammers) totalHammers += r.gap.needsHammers;
    if (r.gap?.needsMythicGears) totalMg += r.gap.needsMythicGears;
    if (r.gap?.mgCost) totalMg += r.gap.mgCost;
    if (r.gap?.mithrilCost) totalMithril += r.gap.mithrilCost;
  });

  return {
    phase,
    actions: remaining,
    completed: analyzed.filter(x => x.done),
    total: { xp: totalXp, hammers: totalHammers, mg: totalMg, mithril: totalMithril },
  };
};

// ═══════════════════════════════════════════════════════════════════
//   CLAUDE API — parse gear/resources from uploaded images
// ═══════════════════════════════════════════════════════════════════
// ── Robust JSON extractor — handles markdown fences, preamble text, and BOM ──
const extractJson = (text) => {
  if (!text) return null;
  let s = String(text).replace(/^\uFEFF/, '').trim();
  // Strip leading markdown fence
  s = s.replace(/^```(?:json|JSON)?\s*\n?/i, '');
  // Strip trailing fence
  s = s.replace(/\n?\s*```\s*$/i, '');
  s = s.trim();
  // Find first { and matching last }
  const start = s.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escape = false, end = -1;
  for (let i = start; i < s.length; i++) {
    const ch = s[i];
    if (escape) { escape = false; continue; }
    if (inString) {
      if (ch === '\\') escape = true;
      else if (ch === '"') inString = false;
    } else {
      if (ch === '"') inString = true;
      else if (ch === '{') depth++;
      else if (ch === '}') {
        depth--;
        if (depth === 0) { end = i; break; }
      }
    }
  }
  if (end === -1) return null;
  return s.slice(start, end + 1);
};

