// ═══════════════════════════════════════════════════════════════════
// ─── Position of each slot in the in-game gear grid ───
const SLOT_POSITION = {
  helmet: 'top-left',
  gloves: 'top-right',
  chest:  'bottom-left',
  boots:  'bottom-right',
};

// ─── Build human-readable in-game steps for an action ───
const buildInGameSteps = (analyzed, t) => {
  const { action, piece, gap } = analyzed;
  const steps = [];
  if (!piece) return steps;
  // graceful fallback if no translator passed
  const tr = t || ((k, v) => T(k, 'en', v));

  const troop = tr('troop.' + action.troop);
  const slot = tr('slot.' + action.slot);
  const POS_KEY = { helmet: 'pos.tl', gloves: 'pos.tr', chest: 'pos.bl', boots: 'pos.br' };
  const pos = tr(POS_KEY[action.slot] || 'pos.tl');

  steps.push(tr('step.open', { troop }));
  steps.push(tr('step.tap', { slot, pos }));

  if (action.type === 'level') {
    if (piece.level < action.level) {
      const n = action.level - piece.level;
      steps.push(tr('step.enhance', { n, rarity: tr('rarity.' + action.rarity), level: action.level, xp: fmt(gap?.xpCost || 0) }));
    }
  }

  if (action.type === 'ascend') {
    if (piece.rarity === 'mythic' && piece.level < 100) {
      const n = 100 - piece.level;
      steps.push(tr('step.enhance', { n, rarity: tr('rarity.mythic'), level: 100, xp: fmt(gap?.needsXp || 0) }));
    }
    const curMastery = piece.mastery || 0;
    if (curMastery < 10) {
      const n = 10 - curMastery;
      steps.push(tr('step.mastery', { n, hammers: gap?.needsHammers || 0 }));
    }
    steps.push(tr('step.ascend', { mg: gap?.needsMythicGears || 2 }));
  }

  return steps;
};

// ─── Total cost of an action ───
const getTotalCost = (analyzed) => {
  const { gap } = analyzed;
  return {
    xp: (gap?.xpCost || 0) + (gap?.needsXp || 0),
    hammers: gap?.needsHammers || 0,
    mg: (gap?.needsMythicGears || 0) + (gap?.mgCost || 0),
    mithril: gap?.mithrilCost || 0,
  };
};

// ─── Greedy: mark which actions user can afford with current resources ───
const annotateAffordability = (actions, resources) => {
  let remaining = {
    xp: totalXp(resources),
    hammers: resources?.hammers || 0,
    mg: resources?.mythicGears || 0,
    mithril: resources?.mithril || 0,
  };
  return actions.map(a => {
    const cost = getTotalCost(a);
    const canAfford = remaining.xp >= cost.xp
      && remaining.hammers >= cost.hammers
      && remaining.mg >= cost.mg
      && remaining.mithril >= cost.mithril;
    if (canAfford) {
      remaining.xp -= cost.xp;
      remaining.hammers -= cost.hammers;
      remaining.mg -= cost.mg;
      remaining.mithril -= cost.mithril;
    }
    return { ...a, canAfford };
  });
};

// ═══════════════════════════════════════════════════════════════════
//   COST PILL — small affordability indicator
// ═══════════════════════════════════════════════════════════════════
const CostPill = ({ icon, label, cost, have, color }) => {
  const enough = (have || 0) >= cost;
  return (
    <div style={{
      padding: '6px 9px', borderRadius: 7,
      background: enough ? 'rgba(34,197,94,0.08)' : 'rgba(239,68,68,0.07)',
      border: `1px solid ${enough ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)'}`,
      display: 'flex', alignItems: 'center', gap: 6,
      minWidth: 0,
    }}>
      <span style={{ color, flexShrink: 0, display: 'flex' }}>{icon}</span>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          fontSize: 9, color: 'var(--kp-text-dim)', fontWeight: 600,
          letterSpacing: 0.3, textTransform: 'uppercase',
        }}>
          {label}
        </div>
        <div style={{ fontSize: 11.5, fontWeight: 700, color: enough ? '#86efac' : '#fca5a5', whiteSpace: 'nowrap' }}>
          {fmt(cost)}
          <span style={{ color: 'var(--kp-text-faint)', fontSize: 9, marginLeft: 3, fontWeight: 500 }}>
            / {fmt(have || 0)}
          </span>
        </div>
      </div>
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════
//   STEP CARD — friendly card showing what to do step by step in the game
// ═══════════════════════════════════════════════════════════════════
const StepCard = ({ analyzed, stepNumber, hero, resources, onMarkDone, t }) => {
  const { action, piece, canAfford } = analyzed;
  const [showSteps, setShowSteps] = useState(stepNumber === 1);
  const troopName = TROOP_LABEL[action.troop];
  const slotName = SLOT_LABEL[action.slot];
  const troopColor = TROOP_COLOR[action.troop];
  const isAscend = action.type === 'ascend';
  const cost = getTotalCost(analyzed);
  const inGameSteps = buildInGameSteps(analyzed, t);

  const title = isAscend
    ? `Ascend ${slotName} to RED`
    : `Upgrade ${slotName} to ${RARITY_LABEL[action.rarity]} Lv.${action.level}`;

  const canToggle = inGameSteps.length > 0;
  return (
    <div
      className={`kp-card${canAfford ? ' kp-ready' : ''}`}
      onClick={canToggle ? () => setShowSteps(s => !s) : undefined}
      style={{
        background: canAfford
          ? 'linear-gradient(135deg, rgba(34,197,94,0.14), rgba(10,18,32,0.55))'
          : 'linear-gradient(135deg, rgba(201,169,97,0.10), var(--kp-card-bg))',
        border: canAfford
          ? '1.5px solid rgba(34,197,94,0.55)'
          : '1.5px solid rgba(201,169,97,0.35)',
        borderRadius: 12, padding: 13,
        boxShadow: canAfford ? '0 0 20px rgba(34,197,94,0.16)' : '0 0 16px rgba(201,169,97,0.10)',
        cursor: canToggle ? 'pointer' : 'default',
      }}>
      {/* Header row */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 11, marginBottom: 10 }}>
        <div style={{
          width: 32, height: 32, borderRadius: '50%',
          background: canAfford
            ? 'linear-gradient(135deg, #22c55e, #15803d)'
            : 'linear-gradient(135deg, #c9a961, #8b6914)',
          color: canAfford ? '#fff' : '#0f0d0a',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontFamily: 'Cinzel, serif', fontWeight: 900, fontSize: 14,
          flexShrink: 0,
          boxShadow: canAfford ? '0 0 8px rgba(34,197,94,0.5)' : 'none',
        }}>
          {stepNumber}
        </div>
        <GearArt troop={action.troop} slot={action.slot} rarity={isAscend ? 'red' : action.rarity} size={42} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 9, color: troopColor, fontWeight: 800, letterSpacing: 0.5, marginBottom: 1 }}>
            {troopName.toUpperCase()}{hero ? ` · ${hero}` : ''}
          </div>
          <div style={{
            color: 'var(--kp-text)', fontSize: 14, fontWeight: 800,
            fontFamily: 'Cinzel, serif', letterSpacing: 0.3,
          }}>
            {title}
          </div>
          {piece && (
            <div style={{ fontSize: 10, color: 'var(--kp-text-dim)', marginTop: 2 }}>
              {t ? t('ui.now') : 'Now:'} <span style={{ color: RARITY_THEME[piece.rarity]?.edge, fontWeight: 700 }}>
                {RARITY_LABEL[piece.rarity]} L{piece.level}
              </span>
              {piece.mastery ? ` · Mastery Lv.${piece.mastery}` : ''}
            </div>
          )}
        </div>
        {canAfford && (
          <div style={{
            padding: '4px 9px', borderRadius: 6,
            background: 'rgba(34,197,94,0.25)',
            border: '1px solid rgba(34,197,94,0.55)',
            color: '#86efac', fontSize: 9, fontWeight: 800,
            letterSpacing: 0.5, flexShrink: 0,
          }}>
            DO NOW
          </div>
        )}
      </div>

      {/* Compact cost line + How-to link */}
      {piece && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap', marginBottom: showSteps ? 8 : 10 }}>
          {[
            cost.xp > 0 && { icon: <Sparkles size={12} />, c: cost.xp, h: totalXp(resources) },
            cost.hammers > 0 && { icon: <Hammer size={12} />, c: cost.hammers, h: resources.hammers || 0 },
            cost.mithril > 0 && { icon: <Gem size={12} />, c: cost.mithril, h: resources.mithril || 0 },
            cost.mg > 0 && { icon: <Star size={12} />, c: cost.mg, h: resources.mythicGears || 0 },
          ].filter(Boolean).map((it, i) => {
            const ok = (it.h || 0) >= it.c;
            return (
              <span key={i} style={{ display: 'inline-flex', alignItems: 'center', gap: 4, fontSize: 11.5, fontWeight: 700, color: ok ? '#86efac' : '#fca5a5' }}>
                {it.icon}{fmt(it.c)}
                <span style={{ color: 'var(--kp-text-faint)', fontWeight: 500, fontSize: 10 }}>/{fmt(it.h)}</span>
              </span>
            );
          })}
          {inGameSteps.length > 0 && (
            <span style={{
              marginLeft: 'auto', display: 'inline-flex', alignItems: 'center', gap: 3,
              color: '#fbbf24', fontSize: 11, fontWeight: 700,
            }}>
              {t ? t('ui.howTo') : 'How to'}{showSteps ? <ChevronDown size={13} /> : <ChevronRight size={13} />}
            </span>
          )}
        </div>
      )}

      {/* Expanded in-game steps */}
      {showSteps && inGameSteps.length > 0 && (
        <div style={{
          padding: '10px 12px', marginBottom: 10,
          background: 'rgba(0,0,0,0.3)', borderRadius: 8,
          border: '1px solid rgba(201,169,97,0.12)',
        }}>
          {inGameSteps.map((s, i) => (
            <div key={i} style={{
              display: 'flex', gap: 8,
              marginBottom: i < inGameSteps.length - 1 ? 6 : 0,
              fontSize: 12, lineHeight: 1.5, color: '#d4c4a0',
            }}>
              <span style={{ width: 18, flexShrink: 0, color: '#fbbf24', fontWeight: 800, fontFamily: 'Cinzel, serif' }}>{i + 1}.</span>
              <span style={{ flex: 1 }}>{s}</span>
            </div>
          ))}
        </div>
      )}

      {/* No gear warning */}
      {!piece && (
        <div style={{
          padding: '9px 12px',
          background: 'rgba(239,68,68,0.1)',
          border: '1px solid rgba(239,68,68,0.35)',
          borderRadius: 7,
          fontSize: 11, color: '#fca5a5', lineHeight: 1.4,
          marginBottom: 9,
        }}>
          ⚠ No gear in this slot. Tap the empty slot in the hero board above to add one.
        </div>
      )}

      {/* Mark as Done button */}
      {piece && onMarkDone && (
        <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 4 }}>
          <button
            onClick={(e) => { e.stopPropagation(); onMarkDone(analyzed); }}
            className="kp-card"
            style={{
              padding: '7px 14px', borderRadius: 8,
              background: canAfford
                ? 'linear-gradient(135deg, #22c55e, #15803d)'
                : 'rgba(34,197,94,0.12)',
              color: canAfford ? '#fff' : '#86efac',
              border: canAfford ? 'none' : '1px solid rgba(34,197,94,0.4)',
              fontFamily: 'inherit', fontSize: 12, fontWeight: 700,
              cursor: 'pointer',
              display: 'inline-flex', alignItems: 'center', gap: 6,
            }}>
            <Check size={14} />
            {t ? t('btn.done') : 'I did this'}
          </button>
        </div>
      )}
    </div>
  );
};

