// ═══════════════════════════════════════════════════════════════════
//   COMMENTS DISPLAY — shows approved comments from the constant
// ═══════════════════════════════════════════════════════════════════
// Parse a GitHub issue into a comment. Title is the text; optional "— Name"
// suffix sets the author, else the issue author's GitHub login is used.
const parseIssueComment = (issue) => {
  const title = (issue.title || '').trim();
  let text = title, author = issue.user?.login || 'Commander';
  const m = title.match(/^(.*\S)\s+[—–-]\s+(.+)$/);
  if (m) { text = m[1].trim(); author = m[2].trim(); }
  text = text.replace(/^["'“]+|["'”]+$/g, '');
  return { text, author, date: (issue.created_at || '').slice(0, 10) };
};

const CommentsSection = ({ t }) => {
  const [comments, setComments] = useState(APPROVED_COMMENTS);
  const [idx, setIdx] = useState(0);
  const [shown, setShown] = useState(true);

  // Pull approved feedback live from GitHub Issues (labelled). Falls back to
  // the built-in examples if the repo isn't set or the request fails.
  useEffect(() => {
    if (!FEEDBACK_REPO) return;
    let cancelled = false;
    const url = `https://api.github.com/repos/${FEEDBACK_REPO}/issues?state=open&labels=${encodeURIComponent(FEEDBACK_LABEL)}&per_page=30`;
    fetch(url, { headers: { Accept: 'application/vnd.github+json' } })
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (cancelled || !Array.isArray(data)) return;
        const parsed = data.filter(i => !i.pull_request).map(parseIssueComment).filter(c => c.text);
        if (parsed.length) setComments(parsed);
      })
      .catch(() => {});
    return () => { cancelled = true; };
  }, []);

  const n = comments.length;
  useEffect(() => {
    if (n <= 1) return;
    const id = setInterval(() => {
      setShown(false);
      setTimeout(() => { setIdx(i => (i + 1) % n); setShown(true); }, 350);
    }, 5500);
    return () => clearInterval(id);
  }, [n]);

  if (n === 0) return null;
  const c = comments[idx % n];
  const heading = t ? t('section.feedback') : 'COMMANDER FEEDBACK';
  return (
    <div style={{
      background: 'var(--kp-panel)',
      border: '1px solid rgba(201,169,97,0.25)',
      borderRadius: 12, padding: 14, marginTop: 18,
      boxShadow: '0 4px 18px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.06)',
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 7, marginBottom: 11 }}>
        <div style={{ fontSize: 15 }}>💬</div>
        <div style={{
          fontFamily: 'Cinzel, serif', fontSize: 13, fontWeight: 800,
          color: 'var(--kp-text-gold)', letterSpacing: 1.2,
        }}>
          {heading}
        </div>
        <div style={{ flex: 1, height: 1, background: 'linear-gradient(90deg, rgba(201,169,97,0.3), transparent)' }} />
      </div>
      <div style={{
        padding: '12px 14px', borderRadius: 9,
        background: 'var(--kp-surface-3)',
        border: '1px solid rgba(201,169,97,0.18)',
        minHeight: 70,
        display: 'flex', flexDirection: 'column', justifyContent: 'center',
      }}>
        <div style={{
          transition: 'opacity 0.35s ease, transform 0.4s cubic-bezier(.22,.61,.36,1), filter 0.35s ease',
          opacity: shown ? 1 : 0,
          transform: shown ? 'translateY(0) scale(1)' : 'translateY(12px) scale(0.98)',
          filter: shown ? 'blur(0)' : 'blur(1px)',
        }}>
          <div style={{ fontSize: 12.5, fontStyle: 'italic', color: '#d4c4a0', lineHeight: 1.6, marginBottom: 6 }}>
            "{c.text}"
          </div>
          <div style={{ fontSize: 10, color: 'var(--kp-text-dim)', textAlign: 'right', letterSpacing: 0.5 }}>
            — <b style={{ color: 'var(--kp-text-gold)' }}>{c.author}</b>
            {c.date && <span style={{ marginLeft: 6, color: 'var(--kp-text-faint)' }}>· {c.date}</span>}
          </div>
        </div>
      </div>
      {n > 1 && (
        <div style={{ display: 'flex', justifyContent: 'center', gap: 5, marginTop: 9 }}>
          {comments.map((_, i) => (
            <div key={i} style={{
              width: i === (idx % n) ? 16 : 5, height: 5, borderRadius: 99,
              background: i === (idx % n) ? '#fbbf24' : 'rgba(201,169,97,0.3)',
              transition: 'width 0.3s, background 0.3s',
            }} />
          ))}
        </div>
      )}
    </div>
  );
};

