// ═══════════════════════════════════════════════════════════════════
//   ENDGAME SPECIALIZATION — Rally Attack vs Defense Garrison (after Phase 7)
// ═══════════════════════════════════════════════════════════════════
// Codes: [troop][slot] + Red level.  Troop: I=Inf A=Arc C=Cav · Slot: H=Helmet C=Chest G=Gloves B=Boots
const SPEC_TROOP = { I: 'infantry', A: 'archer', C: 'cavalry' };
const SPEC_SLOT = { H: 'helmet', C: 'chest', G: 'gloves', B: 'boots' };
const parseSpec = (code) => ({
  troop: SPEC_TROOP[code[0]],
  slot: SPEC_SLOT[code[1]],
  level: parseInt(code.slice(2), 10),
});
const SPEC_PATHS = {
  offense: {
    label: 'Rally Attack', Icon: Sword, color: '#ef4444',
    phases: [
      { n: 8,  codes: ['AB79', 'AH100'] },
      { n: 9,  codes: ['CB79', 'CH100'] },
      { n: 10, codes: ['IH60'] },
      { n: 11, codes: ['IC99', 'AB99', 'CB99'] },
      { n: 12, codes: ['IB60', 'AG60', 'CG60'] },
      { n: 13, codes: ['IB100', 'AC100', 'CC100'] },
      { n: 14, codes: ['IC100', 'AB100', 'CB100'] },
      { n: 15, codes: ['IH100', 'CG100', 'AG100'] },
    ],
  },
  defense: {
    label: 'Defense Garrison', Icon: Shield, color: '#60a5fa',
    phases: [
      { n: 8,  codes: ['CB79', 'CH100'] },
      { n: 9,  codes: ['IH60', 'IB100', 'IC100'] },
      { n: 10, codes: ['CB99', 'CG60', 'CC100'] },
      { n: 11, codes: ['AB79', 'AB99', 'AH100'] },
      { n: 12, codes: ['AG60', 'AC100'] },
      { n: 13, codes: ['AB100', 'CB100'] },
      { n: 14, codes: ['IH100', 'CG100', 'AG100'] },
    ],
  },
};

// Pieces ascended to Red by the base path (Phases 2 & 6). The two helmets
// (archer/cavalry) and infantry gloves stay Mythic, so the spec must ascend
// them when their turn comes.
const BASE_ASCENDED = new Set([
  'infantry-chest', 'infantry-boots', 'infantry-helmet',
  'archer-boots', 'archer-chest', 'archer-gloves',
  'cavalry-boots', 'cavalry-chest', 'cavalry-gloves',
]);
// Convert a spec path into engine phases (continuing the numbering after Phase 7).
const buildSpecPhases = (specId) => {
  const spec = SPEC_PATHS[specId];
  if (!spec) return [];
  const ascended = new Set(BASE_ASCENDED);
  const phases = spec.phases.map(ph => {
    const actions = [];
    ph.codes.forEach(code => {
      const { troop, slot, level } = parseSpec(code);
      const key = `${troop}-${slot}`;
      if (!ascended.has(key)) {
        actions.push({ type: 'ascend', troop, slot });
        ascended.add(key);
      }
      actions.push({ type: 'level', troop, slot, rarity: 'red', level });
    });
    return {
      phase: ph.n,
      title: `${spec.label} · Phase ${ph.n}`,
      desc: `${spec.label} specialization — push these pieces to their Red targets.`,
      actions,
      spec: specId,
    };
  });
  const last = phases[phases.length - 1];
  phases.push({
    phase: (last ? last.phase : 8) + 1,
    title: 'Build Complete',
    desc: `You've finished the full Red gear path plus the ${spec.label} specialization. Outstanding work, Commander.`,
    actions: [],
    isStop: true,
  });
  return phases;
};
// The active path = base Phases 1–7 + (chosen spec phases, or the chooser at 8).
const buildActivePath = (specId) => {
  const base = SHAKES_PATH.slice(0, 7); // Phases 1–7
  if (specId && SPEC_PATHS[specId]) return [...base, ...buildSpecPhases(specId)];
  return SHAKES_PATH; // 1–7 + the chooser (phase 8)
};

