// Migrate older state shapes to current
const migrateState = (s) => {
  if (!s) return defaultState();
  s.resources = s.resources || {};
  // Old `xp` flat field → xpBanked
  if (s.resources.xp != null && s.resources.xpBanked == null) {
    s.resources.xpBanked = s.resources.xp;
    delete s.resources.xp;
  }
  if (s.resources.xpBanked == null) s.resources.xpBanked = 0;
  // Ensure xpParts exists with all tiers
  s.resources.xpParts = s.resources.xpParts || {};
  XP_TIERS.forEach(t => {
    if (s.resources.xpParts[String(t)] == null) s.resources.xpParts[String(t)] = 0;
  });
  if (s.resources.hammers == null) s.resources.hammers = 0;
  if (s.resources.mithril == null) s.resources.mithril = 0;
  if (s.resources.mythicGears == null) s.resources.mythicGears = 0;
  // Ensure heroImages map exists
  if (!s.heroImages) s.heroImages = {};
  if (s.specialization === undefined) s.specialization = null;
  return s;
};

export default function App() {
  const [state, setState] = useState(null);
  const [apiKey, setApiKey] = useState(null); // null = unloaded; '' = none; 'sk-...' = key
  const [showApiSetup, setShowApiSetup] = useState(false);
  const [apiSetupErrorMode, setApiSetupErrorMode] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [parseError, setParseError] = useState(null);
  const [parsingStatus, setParsingStatus] = useState('');  // detailed status during long parses
  const [editingPiece, setEditingPiece] = useState(null); // { troop, slot, piece }
  const [editingResources, setEditingResources] = useState(false);
  const [lastUploadSummary, setLastUploadSummary] = useState(null); // {heroesApplied, piecesApplied}
  const [pickingTroopFor, setPickingTroopFor] = useState(null); // troop name when picker is open
  const [showFeedback, setShowFeedback] = useState(false);
  const [showAlliance, setShowAlliance] = useState(false);
  const [showGear, setShowGear] = useState(false);
  // App is dark-only — the gold-on-dark theme is the identity.
  const theme = 'dark';
  const [language, setLanguage] = useState(() => {
    try { return localStorage.getItem('kingshot-path-lang') || 'en'; } catch { return 'en'; }
  });
  const [visits, setVisits] = useState(null);

  // Persist language
  useEffect(() => { try { localStorage.setItem('kingshot-path-lang', language); } catch {} }, [language]);

  // Increment visit counter once on mount
  useEffect(() => {
    const STORAGE_HIT_KEY = 'kingshot-path-counted';
    const alreadyCounted = (() => {
      try { return sessionStorage.getItem(STORAGE_HIT_KEY) === '1'; } catch { return false; }
    })();
    const url = alreadyCounted
      ? `${COUNTER_API_BASE}/get/${COUNTER_NAMESPACE}/${COUNTER_KEY}`
      : `${COUNTER_API_BASE}/hit/${COUNTER_NAMESPACE}/${COUNTER_KEY}`;
    fetch(url)
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data && typeof data.value === 'number') {
          setVisits(data.value);
          if (!alreadyCounted) {
            try { sessionStorage.setItem(STORAGE_HIT_KEY, '1'); } catch {}
          }
        }
      })
      .catch(() => {});
  }, []);

  // Derived: is current language RTL?
  const isRTL = LANGUAGES.find(l => l.code === language)?.rtl || false;
  // Bound translation helper for current language
  const t = (key, vars) => T(key, language, vars);

  // Load on mount
  useEffect(() => {
    (async () => {
      try {
        const stored = await window.storage.get(STORAGE_KEY);
        if (stored) setState(migrateState(JSON.parse(stored.value)));
        else setState(defaultState());
      } catch {
        setState(defaultState());
      }
      try {
        const keyStored = await window.storage.get(API_KEY_STORAGE);
        setApiKey(keyStored?.value || '');
      } catch {
        setApiKey('');
      }
    })();
  }, []);

  // Persist state
  useEffect(() => {
    if (!state) return;
    window.storage.set(STORAGE_KEY, JSON.stringify(state)).catch(() => {});
  }, [state]);

  // Persist API key
  useEffect(() => {
    if (apiKey === null) return; // not loaded yet
    if (apiKey) window.storage.set(API_KEY_STORAGE, apiKey).catch(() => {});
    else window.storage.delete(API_KEY_STORAGE).catch(() => {});
  }, [apiKey]);

  const handleUpload = async (files) => {
    setParsing(true);
    setParsingStatus('');
    setParseError(null);
    console.log('[KingshotPath] Upload started with', files.length, 'file(s)');
    try {
      const parsed = await parseImagesViaGemini(files, apiKey, setParsingStatus);
      console.log('[KingshotPath] Parsed result:', parsed);

      const parsedHeroes = parsed.heroes || [];
      const heroesReturned = parsedHeroes.length;
      const rejectedTroops = [];
      const rejectedRarities = [];
      let heroesApplied = 0;
      let piecesApplied = 0;

      // Build the next state synchronously so we can decide success/error
      // accurately right here (a functional setState updater runs later, which
      // previously made this check see stale zero counts and show a false error).
      const next = JSON.parse(JSON.stringify(state));
      // Apply heroes / gear — normalize wording (tier/troop) so model drift
      // doesn't silently drop pieces. Resources are entered manually, not imported.
      parsedHeroes.forEach(h => {
        const troop = normalizeTroop(h.troop);
        if (!troop) {
          console.warn('[KingshotPath] Unknown troop:', h.troop);
          if (h.troop) rejectedTroops.push(String(h.troop));
          return;
        }
        if (h.name) next.heroes[troop] = h.name;
        heroesApplied++;
        if (h.gear) {
          SLOTS.forEach(slot => {
            const g = h.gear[slot];
            if (!g) return;
            const rarity = normalizeRarity(g.rarity);
            if (!rarity) {
              console.warn('[KingshotPath] Unknown rarity for', troop, slot, ':', g.rarity);
              if (g.rarity) rejectedRarities.push(String(g.rarity));
              return;
            }
            next.gear[gearKey(troop, slot)] = {
              rarity,
              level: Math.max(0, parseInt(g.level) || 0),
              mastery: Math.max(0, parseInt(g.mastery) || 0),
            };
            piecesApplied++;
          });
        }
      });

      if (heroesApplied > 0 || piecesApplied > 0) {
        setState(next);
      }

      console.log(`[KingshotPath] Applied: ${heroesApplied} heroes, ${piecesApplied} pieces`);

      if (heroesApplied === 0 && piecesApplied === 0) {
        let msg;
        if (heroesReturned === 0) {
          // Gemini responded but read no heroes from the images
          msg = `Gemini read the images but didn't detect any hero gear panels. Make sure each screenshot shows one hero's full 4-piece gear screen. Or tap any slot below to enter manually.`;
        } else if (rejectedRarities.length || rejectedTroops.length) {
          // It read heroes but we couldn't map the tier/troop wording
          const bits = [];
          if (rejectedRarities.length) bits.push(`tier "${[...new Set(rejectedRarities)].slice(0, 3).join('", "')}"`);
          if (rejectedTroops.length) bits.push(`troop "${[...new Set(rejectedTroops)].slice(0, 3).join('", "')}"`);
          msg = `Gemini detected ${heroesReturned} hero panel(s) but couldn't match the ${bits.join(' and ')} it returned. This usually means the model's wording changed — tap any slot to enter manually, and let me know what you see so I can map it.`;
        } else {
          msg = `Gemini detected ${heroesReturned} hero panel(s) but the gear values were empty. Try clearer, full-screen screenshots, or tap any slot to enter manually.`;
        }
        setParseError(msg);
      } else {
        // Show a success message briefly
        setParseError(null);
        setLastUploadSummary({ heroesApplied, piecesApplied });
        setTimeout(() => setLastUploadSummary(null), 5000);
      }
    } catch (e) {
      console.error('[KingshotPath] Upload error:', e);
      if (e.code === 'AUTH') {
        setApiSetupErrorMode(true);
        setShowApiSetup(true);
        setParseError(null);
      } else if (e.code === 'NETWORK') {
        setParseError('Cannot reach Gemini API. Check your internet connection.');
      } else if (e.code === 'RATE') {
        setParseError('Too many requests — wait a minute (free tier is 15 req/min).');
      } else if (e.code === 'OVERLOADED') {
        setParseError('Gemini servers are busy right now. We tried 3 models and all are overloaded. Wait 1-2 minutes and try again, or enter gear manually by tapping any slot.');
      } else if (e.code === 'PARSE_ERROR') {
        setParseError(`${e.message} You can also enter gear manually by tapping any slot.`);
      } else {
        setParseError(e.message || 'Parsing failed. Try the manual editor for each piece.');
      }
    } finally {
      setParsing(false);
    }
  };

  const updatePiece = (troop, slot, newPiece) => {
    setState(prev => {
      const next = JSON.parse(JSON.stringify(prev));
      if (newPiece == null) delete next.gear[gearKey(troop, slot)];
      else next.gear[gearKey(troop, slot)] = newPiece;
      return next;
    });
  };

  // Hero picker: set the selected hero for a troop
  const pickHeroForTroop = (troop, heroName) => {
    setState(prev => ({
      ...prev,
      heroes: { ...prev.heroes, [troop]: heroName },
    }));
  };

  // Set custom portrait image for a hero (base64 data URL)
  const setHeroImage = (heroName, dataUrl) => {
    setState(prev => ({
      ...prev,
      heroImages: { ...(prev.heroImages || {}), [heroName]: dataUrl },
    }));
  };

  // Remove custom portrait for a hero
  const clearHeroImage = (heroName) => {
    setState(prev => {
      const next = { ...prev, heroImages: { ...(prev.heroImages || {}) } };
      delete next.heroImages[heroName];
      return next;
    });
  };

  // Mark a step as done — applies its effect to gear + deducts resources
  const handleMarkDone = (analyzed) => {
    const { action, piece } = analyzed;
    if (!piece) return;
    const cost = getTotalCost(analyzed);

    setState(prev => {
      const next = JSON.parse(JSON.stringify(prev));
      const key = gearKey(action.troop, action.slot);
      const current = next.gear[key] || { rarity: 'mythic', level: 0, mastery: 0 };

      if (action.type === 'level') {
        // Push to target level (keep mastery as-is)
        next.gear[key] = {
          ...current,
          rarity: action.rarity,
          level: action.level,
          mastery: current.mastery || 0,
        };
      } else if (action.type === 'ascend') {
        // Ascend to Red: enhancement restarts at +1 (the in-game display),
        // mastery carries over (it was ≥10 to qualify for ascension).
        next.gear[key] = {
          rarity: 'red',
          level: 1,
          mastery: current.mastery || 0,
        };
      }

      // Deduct resources (cap at 0)
      spendXp(next.resources, cost.xp);
      next.resources.hammers = Math.max(0, (next.resources.hammers || 0) - cost.hammers);
      next.resources.mythicGears = Math.max(0, (next.resources.mythicGears || 0) - cost.mg);
      next.resources.mithril = Math.max(0, (next.resources.mithril || 0) - cost.mithril);

      return next;
    });
  };

  const resetAll = () => {
    if (typeof window !== 'undefined' && window.confirm) {
      // Some artifact environments block confirm, but try anyway
    }
    setState(defaultState());
  };

  if (!state) {
    return (
      <div style={{
        minHeight: '100vh',
        background: 'radial-gradient(ellipse at top, #1a120a, #0a0805)',
        color: 'var(--kp-text-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontFamily: 'Inter, sans-serif',
      }}>
        Loading...
      </div>
    );
  }

  const activePath = buildActivePath(state.specialization);
  const setSpecialization = (spec) => setState(prev => ({ ...prev, specialization: spec }));

  const analysis = computeNextActions(state.gear, state.resources, activePath);
  const { phase, actions, completed = [], total } = analysis;
  const phaseProgress = phase.actions.length > 0
    ? completed.length / phase.actions.length
    : 1;

  const hasAnyGear = Object.keys(state.gear).length > 0;
  const canAfford = (cost, key) => {
    if (key === 'xp') return totalXp(state.resources) >= cost;
    return (state.resources[key] || 0) >= cost;
  };

  const isLight = theme === 'light';
  const themeVars = {
    '--kp-text':        isLight ? '#3a2810' : '#e8dcc4',
    '--kp-text-dim':    isLight ? '#6b5836' : '#94a3bd',
    '--kp-text-gold':   isLight ? '#8a5a14' : '#c9a961',
    '--kp-text-faint':  isLight ? '#8a7656' : '#6b7689',
    '--kp-text-fainter':isLight ? '#a08a64' : '#4a5468',
    '--kp-card-bg':     isLight ? 'rgba(255,251,242,0.78)' : 'rgba(26,38,58,0.92)',
    '--kp-surface-2':   isLight ? 'rgba(120,90,40,0.10)' : 'rgba(6,12,24,0.5)',
    '--kp-surface-3':   isLight ? 'rgba(120,90,40,0.07)' : 'rgba(6,12,24,0.4)',
    '--kp-modal':       isLight ? 'linear-gradient(155deg, #fffaf0, #f2e4c6)' : 'linear-gradient(160deg, #17273e, #0c1626)',
    '--kp-panel':       isLight ? 'linear-gradient(155deg, rgba(255,251,242,0.96), rgba(247,237,214,0.92))' : 'linear-gradient(160deg, rgba(28,42,66,0.97) 0%, rgba(16,26,42,0.98) 100%)',
  };

  return (
    <div dir={isRTL ? 'rtl' : 'ltr'} lang={language} style={{
      ...themeVars,
      minHeight: '100vh',
      background: theme === 'light'
        ? 'radial-gradient(ellipse at top, #f5e9d0 0%, #e8d4a0 50%, #d4b873 100%)'
        : 'radial-gradient(ellipse at top, #0c1626 0%, #081020 50%, #05080f 100%)',
      color: 'var(--kp-text)',
      fontFamily: 'Inter, sans-serif',
      padding: '20px 14px',
      paddingBottom: 60,
      transition: 'background 0.4s, color 0.4s',
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@500;600;700;800&family=Inter:wght@300;400;500;600;700;800&display=swap');
        * { box-sizing: border-box; }
        body { margin: 0; background: ${theme === 'light' ? '#e8d4a0' : '#05080f'}; }
        button { font-family: inherit; transition: transform .12s ease, filter .14s ease, box-shadow .18s ease, background .18s ease; }
        @media (hover: hover) { button:hover { filter: brightness(1.08); } }
        button:active { transform: scale(0.97); }
        input { font-family: inherit; transition: border-color .15s ease, box-shadow .15s ease; }
        input::-webkit-outer-spin-button, input::-webkit-inner-spin-button { -webkit-appearance: none; margin: 0; }
        input[type=number] { -moz-appearance: textfield; }

        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes kpRise { from { opacity: 0; } to { opacity: 1; } }
        @keyframes kpReadyGlow {
          0%, 100% { box-shadow: 0 0 9px rgba(34,197,94,0.12); }
          50%      { box-shadow: 0 0 15px rgba(34,197,94,0.24); }
        }
        @keyframes kpShimmer { 0% { transform: translateX(-120%); } 100% { transform: translateX(220%); } }
        @keyframes kpSheen { 0%, 60% { transform: translateX(-150%) rotate(8deg); } 100% { transform: translateX(220%) rotate(8deg); } }

        /* entrance — staggered via inline animation-delay where used */
        .kp-rise { animation: kpRise .5s cubic-bezier(.22,.61,.36,1) both; }
        /* tappable cards lift slightly */
        .kp-card { transition: transform .16s ease, box-shadow .2s ease, border-color .2s ease; }
        @media (hover: hover) { .kp-card:hover { transform: translateY(-2px); } }
        /* affordable / ready actions gently pulse to draw the eye */
        .kp-ready { animation: kpReadyGlow 3.6s ease-in-out infinite; }
        /* progress bar shimmer overlay */
        .kp-prog { position: relative; overflow: hidden; }
        .kp-prog::after {
          content: ''; position: absolute; top: 0; left: 0; height: 100%; width: 40%;
          background: linear-gradient(90deg, transparent, rgba(255,255,255,0.45), transparent);
          animation: kpShimmer 2.6s ease-in-out infinite;
        }
        /* gear-tile light sweep */
        .kp-sheen { position: absolute; top: -30%; left: 0; width: 45%; height: 160%; z-index: 3;
          background: linear-gradient(90deg, transparent, rgba(255,255,255,0.45), transparent);
          pointer-events: none; animation: kpSheen 5.5s ease-in-out infinite; }

        @media (prefers-reduced-motion: reduce) {
          *, *::before, *::after { animation-duration: 0.001ms !important; animation-iteration-count: 1 !important; transition-duration: 0.001ms !important; }
        }

        @media (max-width: 640px) {
          .heroes-grid { grid-template-columns: 1fr !important; }
        }
      `}</style>

      <div className="kp-rise" style={{ maxWidth: 920, margin: '0 auto' }}>
        {/* Top bar — language picker, easy to reach */}
        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 8 }}>
          <LanguagePicker language={language} onLanguageChange={setLanguage} t={t} />
        </div>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: 18, position: 'relative' }}>
          {/* xXx Commanders banner */}
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 9,
            padding: '5px 14px', borderRadius: 99, marginBottom: 9,
            background: 'linear-gradient(135deg, rgba(239,68,68,0.18), rgba(127,29,29,0.4))',
            border: '1px solid rgba(239,68,68,0.5)',
            boxShadow: '0 0 14px rgba(239,68,68,0.25)',
          }}>
            <span style={{
              fontFamily: 'Cinzel, serif', fontSize: 13, fontWeight: 900,
              color: '#fca5a5', letterSpacing: 2,
              textShadow: '0 0 8px rgba(239,68,68,0.6)',
            }}>
              xXx COMMANDERS
            </span>
            <span style={{ fontSize: 9, color: 'var(--kp-text-dim)', fontWeight: 700, letterSpacing: 0.6 }}>
              KINGDOM 1494
            </span>
          </div>
          <div style={{
            fontFamily: 'Cinzel, serif', fontSize: 22, fontWeight: 900,
            color: '#ef4444', letterSpacing: 1.5, lineHeight: 1.1,
            textShadow: '0 0 16px rgba(239,68,68,0.55), 0 1px 2px rgba(0,0,0,0.5)',
          }}>
            {BRAND_TITLE}
          </div>
          <div style={{ fontSize: 10, color: 'var(--kp-text-dim)', letterSpacing: 0.6, marginTop: 4 }}>
            {t('brand.subtitle')}
          </div>
          <div style={{ fontSize: 10, color: '#c79a6a', letterSpacing: 0.5, marginTop: 3 }}>
            Guide by {GUIDE_AUTHOR} · App by <span style={{ color: '#fbbf24', fontWeight: 700 }}>{APP_AUTHOR}</span>
          </div>
        </div>

        {/* API status / settings strip */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '8px 11px', marginBottom: 12,
          background: apiKey ? 'rgba(34,197,94,0.06)' : 'rgba(251,191,36,0.06)',
          border: apiKey ? '1px solid rgba(34,197,94,0.3)' : '1px dashed rgba(251,191,36,0.4)',
          borderRadius: 9,
        }}>
          {apiKey ? (
            <>
              <Check size={14} color="#86efac" />
              <div style={{ flex: 1, fontSize: 11, color: '#86efac', fontWeight: 600 }}>
                API connected · auto-OCR ready
              </div>
              <button onClick={() => { setApiSetupErrorMode(false); setShowApiSetup(true); }} style={{
                padding: '4px 9px', borderRadius: 5,
                background: 'transparent', border: '1px solid rgba(34,197,94,0.4)',
                color: '#86efac', fontSize: 10, fontWeight: 700,
                cursor: 'pointer',
              }}>
                Change
              </button>
            </>
          ) : (
            <>
              <Info size={14} color="#fbbf24" />
              <div style={{ flex: 1, fontSize: 11, color: '#fbbf24', fontWeight: 600 }}>
                Set up API for photo OCR (optional — manual entry works too)
              </div>
              <button onClick={() => { setApiSetupErrorMode(false); setShowApiSetup(true); }} style={{
                padding: '4px 9px', borderRadius: 5,
                background: 'linear-gradient(135deg, #fbbf24, #b45309)',
                border: 'none', color: '#0f0d0a', fontSize: 10, fontWeight: 800,
                fontFamily: 'Cinzel, serif', letterSpacing: 0.3,
                cursor: 'pointer',
              }}>
                Setup
              </button>
            </>
          )}
        </div>

        {/* Upload */}
        <div style={{ marginBottom: 16 }}>
          <ImageUploader onFilesChosen={handleUpload} disabled={parsing} />
          {parsing && (
            <div style={{
              marginTop: 8, padding: '10px 12px',
              background: 'rgba(34,197,94,0.08)',
              border: '1px solid rgba(34,197,94,0.35)',
              borderRadius: 8, fontSize: 12, color: '#86efac',
              display: 'flex', alignItems: 'center', gap: 9,
            }}>
              <span style={{
                width: 14, height: 14, borderRadius: '50%',
                border: '2px solid rgba(134,239,172,0.3)',
                borderTopColor: '#86efac',
                animation: 'spin 0.8s linear infinite',
                flexShrink: 0,
              }} />
              <span>
                {parsingStatus || 'Analyzing images with Gemini... this takes 5-15 seconds for 4 images.'}
              </span>
            </div>
          )}
          {lastUploadSummary && !parsing && (
            <div style={{
              marginTop: 8, padding: '8px 11px',
              background: 'rgba(34,197,94,0.1)',
              border: '1px solid rgba(34,197,94,0.45)',
              borderRadius: 7, fontSize: 11, color: '#86efac',
              display: 'flex', alignItems: 'center', gap: 6,
            }}>
              <Check size={13} />
              <span>
                Imported {lastUploadSummary.heroesApplied} hero{lastUploadSummary.heroesApplied === 1 ? '' : 'es'}, {lastUploadSummary.piecesApplied} gear piece{lastUploadSummary.piecesApplied === 1 ? '' : 's'}.
              </span>
            </div>
          )}
          {parseError && (
            <div style={{
              marginTop: 8, padding: '8px 11px',
              background: 'rgba(239,68,68,0.1)',
              border: '1px solid rgba(239,68,68,0.4)',
              borderRadius: 7, fontSize: 11, color: '#fca5a5',
              lineHeight: 1.5,
            }}>
              ⚠ {parseError}
            </div>
          )}
          <div style={{ fontSize: 10, color: 'var(--kp-text-fainter)', marginTop: 6, lineHeight: 1.4, textAlign: 'center' }}>
            Upload one screenshot per troop hero (showing all 4 gear pieces). Resources are entered manually below.
            Or tap any slot below to enter gear manually.
          </div>
        </div>

        {/* Resources */}
        <ResourcePills resources={state.resources} onEdit={() => setEditingResources(true)} />

        {/* Phase overview */}
        <PhaseOverview currentPhase={phase} gear={state.gear} path={activePath} />

        {/* Hero selector — pick your 3 march heroes */}
        <HeroSelector
          heroes={state.heroes}
          customImages={state.heroImages || {}}
          onPickTroop={(troop) => setPickingTroopFor(troop)}
        />

        {/* Hero boards — collapsible gear breakdown */}
        <button onClick={() => setShowGear(s => !s)} className="kp-card" style={{
          width: '100%', display: 'flex', alignItems: 'center', gap: 8,
          padding: '10px 14px', borderRadius: 10, marginBottom: showGear ? 10 : 18,
          background: 'var(--kp-panel)', border: '1px solid rgba(201,169,97,0.22)',
          boxShadow: '0 4px 18px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.06)',
          color: 'var(--kp-text-gold)', fontSize: 12, fontWeight: 700,
          fontFamily: 'inherit', cursor: 'pointer', letterSpacing: 0.4,
        }}>
          <Shield size={14} />
          <span style={{ flex: 1, textAlign: 'left' }}>{t('section.gearDetails')}</span>
          {showGear ? <ChevronDown size={15} /> : <ChevronRight size={15} />}
        </button>
        {showGear && (
          <div className="heroes-grid" style={{
            display: 'grid', gridTemplateColumns: '1fr', gap: 10, marginBottom: 18,
          }}>
            {TROOPS.map(t2 => (
              <HeroBoard
                key={t2}
                troop={t2}
                heroName={state.heroes[t2]}
                heroImage={state.heroes[t2] ? state.heroImages?.[state.heroes[t2]] : null}
                gear={state.gear}
                onEdit={(troop, slot) => setEditingPiece({
                  troop, slot,
                  piece: state.gear[gearKey(troop, slot)] || null,
                })}
              />
            ))}
          </div>
        )}

        {/* Current phase card */}
        {hasAnyGear && (
          <div style={{
            background: phase.isStop
              ? 'linear-gradient(135deg, rgba(168,85,247,0.15), rgba(10,18,32,0.7))'
              : 'linear-gradient(135deg, rgba(251,191,36,0.13), rgba(10,18,32,0.7))',
            border: phase.isStop
              ? '1.5px solid rgba(168,85,247,0.5)'
              : '1.5px solid rgba(251,191,36,0.5)',
            borderRadius: 13, padding: 14, marginBottom: 16,
            boxShadow: phase.isStop
              ? '0 0 24px rgba(168,85,247,0.18)'
              : '0 0 24px rgba(251,191,36,0.15)',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10 }}>
              <div style={{
                width: 38, height: 38, borderRadius: '50%',
                background: phase.isStop
                  ? 'linear-gradient(135deg, #a855f7, #581c87)'
                  : 'linear-gradient(135deg, #fbbf24, #b45309)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                color: phase.isStop ? '#fff' : '#0f0d0a',
                fontFamily: 'Cinzel, serif', fontWeight: 900, fontSize: 16,
                boxShadow: phase.isStop ? '0 0 12px rgba(168,85,247,0.4)' : '0 0 12px rgba(251,191,36,0.4)',
              }}>
                {phase.isStop ? <Crown size={18} /> : phase.phase}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 10, color: 'var(--kp-text-dim)', fontWeight: 700, letterSpacing: 0.6 }}>
                  {phase.isStop ? 'PATH COMPLETE' : `PHASE ${phase.phase} · CURRENT`}
                </div>
                <div style={{ fontFamily: 'Cinzel, serif', fontSize: 17, fontWeight: 800, color: 'var(--kp-text)', letterSpacing: 0.4 }}>
                  {phase.title}
                </div>
              </div>
              {!phase.isStop && !phase.isChoose && (
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontSize: 18, fontWeight: 800, color: '#fbbf24', fontFamily: 'Cinzel, serif' }}>
                    {completed.length}/{phase.actions.length}
                  </div>
                  <div style={{ fontSize: 9, color: 'var(--kp-text-dim)', letterSpacing: 0.4, fontWeight: 600 }}>
                    DONE
                  </div>
                </div>
              )}
            </div>
            <div style={{ fontSize: 12, color: '#c0a878', lineHeight: 1.5, whiteSpace: 'pre-line' }}>
              {phase.desc}
            </div>
            {phase.isChoose && (
              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                {[['offense', 'Rally Attack', '#ef4444', Sword], ['defense', 'Defense Garrison', '#60a5fa', Shield]].map(([id, label, color, Icon]) => (
                  <button key={id} onClick={() => setSpecialization(id)} className="kp-card" style={{
                    flex: 1, padding: '11px 8px', borderRadius: 9,
                    background: `linear-gradient(135deg, ${color}, ${color}cc)`,
                    border: 'none', color: '#fff', fontFamily: 'Cinzel, serif', fontWeight: 800, fontSize: 12.5,
                    cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                  }}>
                    <Icon size={15} /> {label}
                  </button>
                ))}
              </div>
            )}
            {!phase.isStop && !phase.isChoose && (
              <div className="kp-prog" style={{
                marginTop: 10, height: 5, borderRadius: 99,
                background: 'var(--kp-surface-2)', overflow: 'hidden',
              }}>
                <div style={{
                  height: '100%', borderRadius: 99,
                  width: `${phaseProgress * 100}%`,
                  background: 'linear-gradient(90deg, #fbbf24, #f97316)',
                  transition: 'width 0.6s cubic-bezier(.22,.61,.36,1)',
                }} />
              </div>
            )}
          </div>
        )}

        {/* Next actions — grouped by affordability with friendly step cards */}
        {hasAnyGear && !phase.isStop && actions.length > 0 && (() => {
          // Sort by total cost (cheapest first) for the affordability annotation
          const sortedByCost = [...actions].sort((a, b) => {
            const ca = getTotalCost(a);
            const cb = getTotalCost(b);
            const totalA = ca.xp + ca.hammers * 100 + ca.mg * 1000;
            const totalB = cb.xp + cb.hammers * 100 + cb.mg * 1000;
            return totalA - totalB;
          });
          const annotated = annotateAffordability(sortedByCost, state.resources);
          const ready = annotated.filter(a => a.canAfford);
          const waiting = annotated.filter(a => !a.canAfford);

          let stepCounter = 0;
          return (
            <div style={{ marginBottom: 16 }}>
              {/* Intro */}
              <div style={{
                padding: '11px 13px', marginBottom: 12, borderRadius: 10,
                background: 'rgba(251,191,36,0.06)',
                border: '1px solid rgba(251,191,36,0.25)',
              }}>
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 7, marginBottom: 5,
                }}>
                  <Target size={15} color="#fbbf24" />
                  <div style={{ fontFamily: 'Cinzel, serif', fontSize: 14, fontWeight: 800, color: '#fbbf24', letterSpacing: 0.4 }}>
                    YOUR ACTION PLAN
                  </div>
                </div>
                <div style={{ fontSize: 11, color: '#c0a878', lineHeight: 1.55 }}>
                  Phase 2 wants you to <b>ascend 7 pieces to Red gear</b>. Below are the {actions.length} that are still pending,
                  ordered by which you can do <b style={{ color: '#86efac' }}>right now</b> with your resources.
                </div>
              </div>

              {/* READY NOW group */}
              {ready.length > 0 && (
                <>
                  <div style={{
                    display: 'flex', alignItems: 'center', gap: 7,
                    marginBottom: 9, marginTop: 4,
                  }}>
                    <div style={{
                      padding: '3px 10px', borderRadius: 99,
                      background: 'rgba(34,197,94,0.2)',
                      border: '1px solid rgba(34,197,94,0.5)',
                      fontSize: 10, fontWeight: 800, color: '#86efac',
                      letterSpacing: 0.5,
                      display: 'flex', alignItems: 'center', gap: 5,
                    }}>
                      <Check size={11} /> READY NOW
                    </div>
                    <div style={{ fontSize: 10, color: 'var(--kp-text-dim)' }}>
                      You have enough resources for {ready.length} {ready.length === 1 ? 'action' : 'actions'}
                    </div>
                    <div style={{ flex: 1, height: 1, background: 'linear-gradient(90deg, rgba(34,197,94,0.3), transparent)' }} />
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 9, marginBottom: 14 }}>
                    {ready.map((a, i) => {
                      stepCounter++;
                      return (
                        <StepCard
                          key={`r-${a.action.troop}-${a.action.slot}-${a.action.type}`}
                          analyzed={a}
                          stepNumber={stepCounter}
                          hero={state.heroes[a.action.troop]}
                          resources={state.resources}
                          onMarkDone={handleMarkDone}
                          t={t}
                        />
                      );
                    })}
                  </div>
                </>
              )}

              {/* NEED MORE group */}
              {waiting.length > 0 && (
                <>
                  <div style={{
                    display: 'flex', alignItems: 'center', gap: 7,
                    marginBottom: 9, marginTop: 4,
                  }}>
                    <div style={{
                      padding: '3px 10px', borderRadius: 99,
                      background: 'rgba(251,191,36,0.15)',
                      border: '1px solid rgba(251,191,36,0.4)',
                      fontSize: 10, fontWeight: 800, color: '#fbbf24',
                      letterSpacing: 0.5,
                      display: 'flex', alignItems: 'center', gap: 5,
                    }}>
                      <AlertTriangle size={10} /> NEED MORE RESOURCES
                    </div>
                    <div style={{ fontSize: 10, color: 'var(--kp-text-dim)' }}>
                      Save up to unlock these {waiting.length}
                    </div>
                    <div style={{ flex: 1, height: 1, background: 'linear-gradient(90deg, rgba(251,191,36,0.3), transparent)' }} />
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 9 }}>
                    {waiting.slice(0, 5).map((a, i) => {
                      stepCounter++;
                      return (
                        <StepCard
                          key={`w-${a.action.troop}-${a.action.slot}-${a.action.type}`}
                          analyzed={a}
                          stepNumber={stepCounter}
                          hero={state.heroes[a.action.troop]}
                          resources={state.resources}
                          onMarkDone={handleMarkDone}
                          t={t}
                        />
                      );
                    })}
                    {waiting.length > 5 && (
                      <div style={{ textAlign: 'center', fontSize: 11, color: 'var(--kp-text-faint)', fontStyle: 'italic', padding: 8 }}>
                        + {waiting.length - 5} more {waiting.length - 5 === 1 ? 'piece' : 'pieces'} also waiting for resources
                      </div>
                    )}
                  </div>
                </>
              )}
            </div>
          );
        })()}

        {/* Cost summary */}
        {hasAnyGear && !phase.isStop && (total.xp > 0 || total.hammers > 0 || total.mg > 0) && (
          <div style={{
            background: 'var(--kp-surface-2)',
            border: '1px solid rgba(201,169,97,0.25)',
            borderRadius: 11, padding: 13, marginBottom: 14,
          }}>
            <div style={{ fontSize: 10, color: 'var(--kp-text-dim)', fontWeight: 700, letterSpacing: 0.5, marginBottom: 9 }}>
              TOTAL COST TO COMPLETE PHASE {phase.phase}
            </div>
            <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
              {total.xp > 0 && (
                <div>
                  <div style={{ fontSize: 9, color: '#22d3ee', fontWeight: 700, letterSpacing: 0.4 }}>XP NEEDED</div>
                  <div style={{ fontSize: 16, fontWeight: 800, color: canAfford(total.xp, 'xp') ? '#86efac' : '#fca5a5', fontFamily: 'Cinzel, serif' }}>
                    {fmt(total.xp)}
                    <span style={{ fontSize: 11, color: 'var(--kp-text-faint)', fontWeight: 500, marginLeft: 5 }}>
                      / {fmt(totalXp(state.resources))} you have
                    </span>
                  </div>
                </div>
              )}
              {total.hammers > 0 && (
                <div>
                  <div style={{ fontSize: 9, color: '#fbbf24', fontWeight: 700, letterSpacing: 0.4 }}>HAMMERS NEEDED</div>
                  <div style={{ fontSize: 16, fontWeight: 800, color: canAfford(total.hammers, 'hammers') ? '#86efac' : '#fca5a5', fontFamily: 'Cinzel, serif' }}>
                    {total.hammers}
                    <span style={{ fontSize: 11, color: 'var(--kp-text-faint)', fontWeight: 500, marginLeft: 5 }}>
                      / {state.resources.hammers || 0} you have
                    </span>
                  </div>
                </div>
              )}
              {total.mg > 0 && (
                <div>
                  <div style={{ fontSize: 9, color: '#a855f7', fontWeight: 700, letterSpacing: 0.4 }}>MYTHIC GEARS</div>
                  <div style={{ fontSize: 16, fontWeight: 800, color: canAfford(total.mg, 'mythicGears') ? '#86efac' : '#fca5a5', fontFamily: 'Cinzel, serif' }}>
                    {total.mg}
                    <span style={{ fontSize: 11, color: 'var(--kp-text-faint)', fontWeight: 500, marginLeft: 5 }}>
                      / {state.resources.mythicGears || 0} you have
                    </span>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Completed actions summary */}
        {hasAnyGear && !phase.isStop && completed.length > 0 && (
          <div style={{
            background: 'rgba(34,197,94,0.06)',
            border: '1px solid rgba(34,197,94,0.25)',
            borderRadius: 11, padding: 12, marginBottom: 14,
          }}>
            <div style={{ fontSize: 10, color: '#86efac', fontWeight: 700, letterSpacing: 0.5, marginBottom: 8 }}>
              <Check size={11} style={{ display: 'inline', verticalAlign: 'middle', marginRight: 4 }} />
              ALREADY DONE IN PHASE {phase.phase}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
              {completed.map((c, i) => {
                const troopName = TROOP_LABEL[c.action.troop];
                const slotName = SLOT_LABEL[c.action.slot];
                const target = c.action.type === 'ascend'
                  ? 'ascended to Red'
                  : `reached ${RARITY_LABEL[c.action.rarity]} Lv.${c.action.level}`;
                return (
                  <div key={i} style={{
                    display: 'flex', alignItems: 'center', gap: 8,
                    padding: '5px 9px', borderRadius: 7,
                    background: 'rgba(34,197,94,0.1)',
                    border: '1px solid rgba(34,197,94,0.3)',
                  }}>
                    <Check size={12} color="#86efac" style={{ flexShrink: 0 }} />
                    <span style={{ fontSize: 11, color: '#d4f4dc' }}>
                      <b style={{ color: TROOP_COLOR[c.action.troop] }}>{troopName}</b> {slotName} — {target}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Endgame specialization — only relevant once the base path (P1–7) is done */}
        {(phase.isChoose || phase.isStop || phase.spec || state.specialization) && (
          <SpecializationTabs active={state.specialization} onChoose={setSpecialization} />
        )}

        <CommentsSection t={t} />

        {/* Alliance / Discord landing + visit counter */}
        <AllianceWidget onJoin={() => setShowAlliance(true)} t={t} />

        {/* Footer — feedback + credits */}
        <Footer
          onFeedback={() => setShowFeedback(true)}
          t={t}
        />

        {/* Visit counter — outside the footer box, above Reset */}
        <VisitCounter visits={visits} t={t} />

        {/* Reset */}
        <div style={{ textAlign: 'center', marginTop: 14 }}>
          <button onClick={resetAll} style={{
            padding: '7px 14px', borderRadius: 7,
            background: 'transparent',
            border: '1px solid rgba(201,169,97,0.2)',
            color: 'var(--kp-text-faint)', fontSize: 11, fontWeight: 600,
            cursor: 'pointer',
            display: 'inline-flex', alignItems: 'center', gap: 5,
          }}>
            <RotateCcw size={12} /> Reset all data
          </button>
        </div>
      </div>

      {/* Modals */}
      {editingPiece && (
        <PieceEditor
          piece={editingPiece.piece}
          onSave={(p) => {
            updatePiece(editingPiece.troop, editingPiece.slot, p);
            setEditingPiece(null);
          }}
          onClose={() => setEditingPiece(null)}
        />
      )}
      {editingResources && (
        <ResourceEditor
          resources={state.resources}
          onSave={(r) => {
            setState(prev => ({ ...prev, resources: r }));
            setEditingResources(false);
          }}
          onClose={() => setEditingResources(false)}
        />
      )}
      {showApiSetup && (
        <ApiSetupModal
          initialKey={apiKey}
          errorMode={apiSetupErrorMode}
          onSave={(k) => {
            setApiKey(k);
            setShowApiSetup(false);
            setApiSetupErrorMode(false);
          }}
          onClose={() => {
            setShowApiSetup(false);
            setApiSetupErrorMode(false);
          }}
        />
      )}
      {pickingTroopFor && (
        <HeroPickerModal
          troop={pickingTroopFor}
          currentHero={state.heroes[pickingTroopFor]}
          onPick={(name) => {
            pickHeroForTroop(pickingTroopFor, name);
            setPickingTroopFor(null);
          }}
          onClose={() => setPickingTroopFor(null)}
        />
      )}
      {showFeedback && (
        <FeedbackModal onClose={() => setShowFeedback(false)} />
      )}
      {showAlliance && (
        <AllianceModal onClose={() => setShowAlliance(false)} />
      )}
    </div>
  );
}
